const e={pending:{label:`در انتظار تأیید`,class:`badge-warning`},approved:{label:`تأیید شده`,class:`badge-success`},supervisor_assigned:{label:`استاد راهنما تعیین شده`,class:`badge-info`},topic_proposal:{label:`پیشنهاد موضوع`,class:`badge-warning`},topic_approved:{label:`موضوع تأیید شده`,class:`badge-success`},in_progress:{label:`در حال انجام`,class:`badge-info`},defense_scheduled:{label:`زمان دفاع تعیین شده`,class:`badge-info`},completed:{label:`تکمیل شده`,class:`badge-success`},rejected:{label:`رد شده`,class:`badge-danger`}};function t(t){return e[t]?.label||t}function n(t){return e[t]?.class||`badge-info`}export{t as n,n as t};